db_schema:
PRAGMA foreign_keys = ON;

CREATE TABLE categories (
	id TEXT PRIMARY KEY,
	name TEXT NOT NULL,
	department TEXT NOT NULL
);

CREATE TABLE product_kinds (
	id TEXT PRIMARY KEY,
	category_id TEXT NOT NULL,
	name TEXT NOT NULL
);

CREATE TABLE families (
	id TEXT PRIMARY KEY,
	category_id TEXT NOT NULL,
	kind_id TEXT NOT NULL,
	brand TEXT NOT NULL,
	series TEXT NOT NULL,
	model TEXT NOT NULL,
	name TEXT NOT NULL,
	properties TEXT NOT NULL
);

CREATE TABLE products (
	sku TEXT PRIMARY KEY,
	path TEXT NOT NULL,
	category_id TEXT NOT NULL,
	kind_id TEXT NOT NULL,
	family_id TEXT NOT NULL,
	brand TEXT NOT NULL,
	series TEXT NOT NULL,
	model TEXT NOT NULL,
	name TEXT NOT NULL,
	properties TEXT NOT NULL
);

CREATE TABLE product_properties (
	sku TEXT NOT NULL,
	key TEXT NOT NULL,
	value_text TEXT NOT NULL,
	value_number REAL,
	PRIMARY KEY (sku, key)
);

CREATE TABLE inventory (
	store_id TEXT NOT NULL,
	sku TEXT NOT NULL,
	on_hand INTEGER NOT NULL,
	reserved INTEGER NOT NULL,
	available_today INTEGER NOT NULL,
	incoming_quantity INTEGER NOT NULL,
	next_arrival_in_days INTEGER,
	PRIMARY KEY (store_id, sku),
	FOREIGN KEY (sku) REFERENCES products(sku)
);

CREATE INDEX product_properties_key_text_idx ON product_properties(key, value_text);
CREATE INDEX products_brand_idx ON products(brand);
CREATE INDEX products_kind_idx ON products(kind_id);
CREATE INDEX inventory_sku_idx ON inventory(sku);
